#include<bits/stdc++.h>
using namespace std;
struct node{
    int a,b;
}c[105];
double tot;
int x=0;
bool cmp(node x,node y)
{
	return x.b*y.a>y.b*x.a;
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&c[i].a,&c[i].b);
    }
    sort(c+1,c+n+1,cmp);
	x=m;
	int i;
    for(i=1;i<=n;i++)
    {
		if(x<c[i].a)
		{
			break;
		}
		tot+=c[i].b;
		x-=c[i].a;
    }
    if(i<n)
    {
    	tot+=1.0*x*c[i].b/c[i].a;
	}
    printf("%0.2lf",tot);
    return 0;
}
